/**
 * @name Taint flow from network input to File/Path construction
 * @description Detects potential path traversal vulnerabilities where network-received data flows to file system operations
 * @kind path-problem
 * @problem.severity error
 * @id java/path-traversal-rocketmq-1
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module PathTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor sinks
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getArgument(0)
    )
    or
    // FileInputStream constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileInputStream") and
      sink.asExpr() = ce.getArgument(0)
    )
    or
    // FileOutputStream constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileOutputStream") and
      sink.asExpr() = ce.getArgument(0)
    )
    or
    // Paths.get sinks
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Path.resolve sinks
    exists(MethodCall mc |
      mc.getMethod().hasName("resolve") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.nio.file", "Path") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module PathTraversalFlow = TaintTracking::Global<PathTraversalConfig>;
import PathTraversalFlow::PathGraph

from PathTraversalFlow::PathNode source, PathTraversalFlow::PathNode sink
where PathTraversalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential path traversal: data from $@ flows to file operation.", source.getNode(), "network input"

/**
 * @name AclUtils.getYamlDataObject file path taint analysis
 * @description Check if external input can reach the file path in AclUtils.getYamlDataObject
 * @kind path-problem
 * @problem.severity error
 * @id java/rocketmq-acl-yaml-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

// Find where AclUtils.getYamlDataObject is called and what paths flow into it
module AclPathConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
    or
    // Also consider parameters from network-related request handling
    exists(Parameter p |
      source.asParameter() = p and
      p.getCallable().getDeclaringType().getPackage().getName().matches("org.apache.rocketmq.%") and
      (
        p.getType().(RefType).hasQualifiedName("org.apache.rocketmq.remoting.protocol", "RemotingCommand") or
        p.getType().(RefType).getASupertype*().hasQualifiedName("org.apache.rocketmq.remoting.protocol", "RemotingCommand")
      )
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // AclUtils.getYamlDataObject call
    exists(MethodCall mc |
      mc.getMethod().hasName("getYamlDataObject") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.apache.rocketmq.acl.common", "AclUtils") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Any File construction in acl module
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      ce.getEnclosingCallable().getDeclaringType().getPackage().getName().matches("org.apache.rocketmq.acl%") and
      sink.asExpr() = ce.getArgument(0)
    )
  }
}

