/**
 * @name RocketMQ network request to ACL file operation taint flow
 * @description Trace taint from RemotingCommand fields through AdminBrokerProcessor to ACL file operations
 * @kind path-problem
 * @problem.severity error
 * @id java/rocketmq-network-to-acl-file
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-073
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module AclFileTaintConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // RemotingCommand.getExtFields() or header field getters
    exists(MethodCall mc |
      source.asExpr() = mc and
      (
        (mc.getMethod().hasName("getExtFields") and
         mc.getQualifier().getType().(RefType).hasQualifiedName("org.apache.rocketmq.remoting.protocol", "RemotingCommand"))
        or
        (mc.getMethod().hasName("decodeCommandCustomHeader") and
         mc.getQualifier().getType().(RefType).hasQualifiedName("org.apache.rocketmq.remoting.protocol", "RemotingCommand"))
        or
        // Field getters on decoded headers (e.g., DeleteAccessConfigRequestHeader.getAccessKey())
        (mc.getMethod().getDeclaringType().getPackage().getName().matches("org.apache.rocketmq.common.protocol.header%") and
         mc.getMethod().getName().matches("get%"))
      )
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // PlainPermissionManager file operations
    exists(MethodCall mc |
      (mc.getMethod().hasName("deleteAccessConfig") or
       mc.getMethod().hasName("updateAccessConfig") or
       mc.getMethod().hasName("updateGlobalWhiteAddrsConfig")) and
      mc.getMethod().getDeclaringType().getPackage().getName().matches("org.apache.rocketmq.acl%") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Direct File construction
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getArgument(0)
    )
    or
    // AclUtils.getYamlDataObject
    exists(MethodCall mc |
      mc.getMethod().hasName("getYamlDataObject") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.apache.rocketmq.acl.common", "AclUtils") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

