/**
 * @name Network to PlainPermissionManager file write - extended taint tracking
 * @description Full taint flow: RemotingCommand → AdminBrokerProcessor → PlainPermissionManager → AclUtils file write
 * @kind path-problem
 * @problem.severity error
 * @id java/rocketmq-full-network-to-file-write
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-073
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module NetworkToFileWriteConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Header field getters on DeleteAccessConfigRequestHeader, UpdateGlobalWhiteAddrsConfigRequestHeader
    exists(MethodCall mc |
      source.asExpr() = mc and
      mc.getMethod().getDeclaringType().getPackage().getName().matches("org.apache.rocketmq.common.protocol.header%") and
      mc.getMethod().getName().matches("get%")
    )
    or
    // decodeCommandCustomHeader result
    exists(MethodCall mc |
      source.asExpr() = mc and
      mc.getMethod().hasName("decodeCommandCustomHeader") and
      mc.getQualifier().getType().(RefType).hasQualifiedName("org.apache.rocketmq.remoting.protocol", "RemotingCommand")
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // writeDataObject in AclUtils
    exists(MethodCall mc |
      mc.getMethod().hasName("writeDataObject") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.apache.rocketmq.acl.common", "AclUtils") and
      (sink.asExpr() = mc.getArgument(0) or sink.asExpr() = mc.getArgument(1))
    )
    or
    // getYamlDataObject in AclUtils 
    exists(MethodCall mc |
      mc.getMethod().hasName("getYamlDataObject") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.apache.rocketmq.acl.common", "AclUtils") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // FileOutputStream/FileWriter
    exists(ClassInstanceExpr ce |
      (ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileOutputStream") or
       ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileWriter")) and
      sink.asExpr() = ce.getArgument(0)
    )
  }

  predicate isAdditionalFlowStep(DataFlow::Node node1, DataFlow::Node node2) {
    // PlainAccessValidator.deleteAccessConfig parameter → PlainPermissionManager.deleteAccessConfig call
    exists(MethodCall mc |
      mc.getMethod().hasName("deleteAccessConfig") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.apache.rocketmq.acl.plain", "PlainPermissionManager") and
      node1.asExpr() = mc.getAnArgument() and
      node2.asExpr() = mc
    )
    or
    // PlainAccessValidator.updateGlobalWhiteAddrsConfig parameter
    exists(MethodCall mc |
      mc.getMethod().hasName("updateGlobalWhiteAddrsConfig") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.apache.rocketmq.acl.plain", "PlainPermissionManager") and
      node1.asExpr() = mc.getAnArgument() and
      node2.asExpr() = mc
    )
    or
    // UtilAll.String2List
    exists(MethodCall mc |
      mc.getMethod().hasName("String2List") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.apache.rocketmq.common", "UtilAll") and
      node1.asExpr() = mc.getAnArgument() and
      node2.asExpr() = mc
    )
  }
}

