/**
 * @name Network request to PlainAccessConfig to ACL file write - precise end-to-end taint
 * @description Precise taint: CreateAccessConfigRequestHeader → PlainAccessConfig → PlainPermissionManager.updateAccessConfig → AclUtils.writeDataObject/getYamlDataObject
 * @kind path-problem
 * @problem.severity error
 * @id java/rocketmq-precise-network-acl-file
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-073
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module PreciseAclFileConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // CreateAccessConfigRequestHeader getters called in AdminBrokerProcessor
    exists(MethodCall mc |
      source.asExpr() = mc and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.apache.rocketmq.common.protocol.header", "CreateAccessConfigRequestHeader") and
      mc.getMethod().getName().matches("get%") and
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.apache.rocketmq.broker.processor", "AdminBrokerProcessor")
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // writeDataObject in AclUtils
    exists(MethodCall mc |
      mc.getMethod().hasName("writeDataObject") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.apache.rocketmq.acl.common", "AclUtils") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // getYamlDataObject in AclUtils (file read/write path)
    exists(MethodCall mc |
      mc.getMethod().hasName("getYamlDataObject") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.apache.rocketmq.acl.common", "AclUtils") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // File constructor in ACL module
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      ce.getEnclosingCallable().getDeclaringType().getPackage().getName().matches("org.apache.rocketmq.acl%") and
      sink.asExpr() = ce.getArgument(0)
    )
    or
    // FileOutputStream
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileOutputStream") and
      sink.asExpr() = ce.getArgument(0)
    )
  }
}

module PreciseAclFileFlow = TaintTracking::Global<PreciseAclFileConfig>;
import PreciseAclFileFlow::PathGraph

from PreciseAclFileFlow::PathNode source, PreciseAclFileFlow::PathNode sink
where PreciseAclFileFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "CONFIRMED: CreateAccessConfigRequestHeader field $@ flows to file operation in ACL module.", source.getNode(), "network request field"
